oldWay:
/* transform is a single property — they overwrite each other */
.card {
  transform: rotate(-3deg);
}
.card:hover {
  transform: scale(1.05);
  /* The rotate is gone — transform is now only scale */
}

modernWay:
.card {
  rotate: -3deg;
}
.card:hover {
  scale: 1.05;
  /* rotate is untouched — they are independent properties */
}

startingCSS:
.demo {
  display: flex;
  gap: 1.5rem;
  padding: 2rem;
  background: #0f172a;
  border-radius: 12px;
  justify-content: center;
}

.card {
  width: 180px;
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 10px;
  padding: 1.25rem;
  text-align: center;
  color: #e2e8f0;
  cursor: pointer;
  transition: scale 0.2s, transform 0.2s;
}

.card strong {
  display: block;
  font-size: 0.9rem;
  margin-bottom: 0.5rem;
}

.card p {
  font-size: 0.75rem;
  color: #94a3b8;
  margin: 0 0 0.5rem;
  line-height: 1.4;
}

.card small {
  font-size: 0.65rem;
  color: #475569;
  font-style: italic;
}

/* Old way: transform property overwrites itself */
.broken { transform: rotate(-3deg); }
.broken:hover { transform: scale(1.08); }

/* New way: individual properties stack */
.modern { rotate: -3deg; }
.modern:hover {
  /* Add scale: 1.08 here — the rotate stays */
}
